import{_ as a,c as t,o as i,a1 as d}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Funciones avanzadas","description":"Aprende la configuración avanzada de Clawdbot, incluyendo configuración de modelos de IA, colaboración de múltiples agentes, automatización del navegador, herramientas de ejecución de comandos, herramientas de búsqueda web, interfaz visual Canvas, activación por voz y TTS, sistema de memoria, tareas programadas Cron, plataforma de habilidades, sandbox de seguridad y Gateway remoto.","frontmatter":{"title":"Funciones avanzadas","sidebarTitle":"Desbloquea los superpoderes de la IA","subtitle":"Funciones avanzadas","description":"Aprende la configuración avanzada de Clawdbot, incluyendo configuración de modelos de IA, colaboración de múltiples agentes, automatización del navegador, herramientas de ejecución de comandos, herramientas de búsqueda web, interfaz visual Canvas, activación por voz y TTS, sistema de memoria, tareas programadas Cron, plataforma de habilidades, sandbox de seguridad y Gateway remoto.","prerequisite":["start/getting-started","start/gateway-startup"],"order":185},"headers":[],"relativePath":"es/moltbot/moltbot/advanced/index.md","filePath":"es/moltbot/moltbot/advanced/index.md"}'),r={name:"es/moltbot/moltbot/advanced/index.md"};function o(n,e,s,l,c,u){return i(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="funciones-avanzadas" tabindex="-1">Funciones avanzadas <a class="header-anchor" href="#funciones-avanzadas" aria-label="Permalink to &quot;Funciones avanzadas&quot;">​</a></h1><h2 id="resumen-del-capitulo" tabindex="-1">Resumen del capítulo <a class="header-anchor" href="#resumen-del-capitulo" aria-label="Permalink to &quot;Resumen del capítulo&quot;">​</a></h2><p>Este capítulo presenta en profundidad las funciones avanzadas de Clawdbot, ayudándote a aprovechar al máximo las potentes capacidades del asistente de IA. Desde la configuración de modelos de IA y la colaboración de múltiples agentes, hasta la automatización del navegador, el sistema de memoria y las funciones de voz, puedes elegir aprender según tus necesidades.</p><div class="info custom-block"><p class="custom-block-title">Prerrequisitos</p><p>Antes de estudiar este capítulo, completa lo siguiente:</p><ul><li><a href="./../../start/getting-started/">Inicio rápido</a></li><li><a href="./../../start/gateway-startup/">Iniciar Gateway</a></li></ul></div><h2 id="rutas-de-aprendizaje" tabindex="-1">Rutas de aprendizaje <a class="header-anchor" href="#rutas-de-aprendizaje" aria-label="Permalink to &quot;Rutas de aprendizaje&quot;">​</a></h2><p>Según tus necesidades, puedes elegir diferentes rutas de aprendizaje:</p><h3 id="🚀-ruta-rapida-recomendada-para-principiantes" tabindex="-1">🚀 Ruta rápida (recomendada para principiantes) <a class="header-anchor" href="#🚀-ruta-rapida-recomendada-para-principiantes" aria-label="Permalink to &quot;🚀 Ruta rápida (recomendada para principiantes)&quot;">​</a></h3><ol><li><a href="./models-auth/">Configuración de modelos de IA y autenticación</a> - Configura tus modelos de IA favoritos</li><li><a href="./tools-exec/">Herramientas de ejecución de comandos y aprobación</a> - Permite que la IA ejecute comandos de forma segura</li><li><a href="./tools-web/">Herramientas de búsqueda y scraping web</a> - Expande la capacidad de adquisición de conocimientos de la IA</li></ol><h3 id="🤖-ruta-de-expansion-de-capacidades-de-ia" tabindex="-1">🤖 Ruta de expansión de capacidades de IA <a class="header-anchor" href="#🤖-ruta-de-expansion-de-capacidades-de-ia" aria-label="Permalink to &quot;🤖 Ruta de expansión de capacidades de IA&quot;">​</a></h3><ol><li><a href="./session-management/">Gestión de sesiones y múltiples agentes</a> - Comprende el mecanismo de colaboración de IA</li><li><a href="./memory-system/">Sistema de memoria y búsqueda vectorial</a> - Permite que la IA recuerde información importante</li><li><a href="./skills-platform/">Plataforma de habilidades y ClawdHub</a> - Usa y comparte paquetes de habilidades</li></ol><h3 id="🔧-ruta-de-herramientas-de-automatizacion" tabindex="-1">🔧 Ruta de herramientas de automatización <a class="header-anchor" href="#🔧-ruta-de-herramientas-de-automatizacion" aria-label="Permalink to &quot;🔧 Ruta de herramientas de automatización&quot;">​</a></h3><ol><li><a href="./tools-browser/">Herramientas de automatización del navegador</a> - Automatización de operaciones web</li><li><a href="./cron-automation/">Tareas programadas Cron y Webhook</a> - Tareas programadas y activación de eventos</li><li><a href="./remote-gateway/">Gateway remoto y Tailscale</a> - Acceso remoto a tu asistente de IA</li></ol><h3 id="🎨-ruta-de-experiencia-interactiva" tabindex="-1">🎨 Ruta de experiencia interactiva <a class="header-anchor" href="#🎨-ruta-de-experiencia-interactiva" aria-label="Permalink to &quot;🎨 Ruta de experiencia interactiva&quot;">​</a></h3><ol><li><a href="./canvas/">Interfaz visual Canvas y A2UI</a> - Interfaz interactiva visual</li><li><a href="./voice-tts/">Activación por voz y texto a voz</a> - Funciones de interacción por voz</li></ol><h3 id="🔒-ruta-de-seguridad-y-despliegue" tabindex="-1">🔒 Ruta de seguridad y despliegue <a class="header-anchor" href="#🔒-ruta-de-seguridad-y-despliegue" aria-label="Permalink to &quot;🔒 Ruta de seguridad y despliegue&quot;">​</a></h3><ol><li><a href="./security-sandbox/">Seguridad y aislamiento en sandbox</a> - Comprende en profundidad los mecanismos de seguridad</li><li><a href="./remote-gateway/">Gateway remoto y Tailscale</a> - Acceso remoto seguro</li></ol><h2 id="navegacion-de-subpaginas" tabindex="-1">Navegación de subpáginas <a class="header-anchor" href="#navegacion-de-subpaginas" aria-label="Permalink to &quot;Navegación de subpáginas&quot;">​</a></h2><h3 id="configuracion-central" tabindex="-1">Configuración central <a class="header-anchor" href="#configuracion-central" aria-label="Permalink to &quot;Configuración central&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tema</th><th>Descripción</th><th>Tiempo estimado</th></tr></thead><tbody><tr><td><a href="./models-auth/">Configuración de modelos de IA y autenticación</a></td><td>Configura múltiples proveedores de modelos de IA como Anthropic, OpenAI, OpenRouter, Ollama y métodos de autenticación</td><td>15 minutos</td></tr><tr><td><a href="./session-management/">Gestión de sesiones y múltiples agentes</a></td><td>Aprende el modelo de sesión, aislamiento de sesión, colaboración de sub-agentes, compresión de contexto y otros conceptos centrales</td><td>20 minutos</td></tr></tbody></table><h3 id="sistema-de-herramientas" tabindex="-1">Sistema de herramientas <a class="header-anchor" href="#sistema-de-herramientas" aria-label="Permalink to &quot;Sistema de herramientas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tema</th><th>Descripción</th><th>Tiempo estimado</th></tr></thead><tbody><tr><td><a href="./tools-browser/">Herramientas de automatización del navegador</a></td><td>Usa herramientas de navegador para automatización web, capturas de pantalla, operaciones de formularios, etc.</td><td>25 minutos</td></tr><tr><td><a href="./tools-exec/">Herramientas de ejecución de comandos y aprobación</a></td><td>Configura y usa la herramienta exec, comprende el mecanismo de aprobación de seguridad y control de permisos</td><td>15 minutos</td></tr><tr><td><a href="./tools-web/">Herramientas de búsqueda y scraping web</a></td><td>Usa las herramientas web_search y web_fetch para búsqueda web y scraping de contenido</td><td>20 minutos</td></tr></tbody></table><h3 id="experiencia-interactiva" tabindex="-1">Experiencia interactiva <a class="header-anchor" href="#experiencia-interactiva" aria-label="Permalink to &quot;Experiencia interactiva&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tema</th><th>Descripción</th><th>Tiempo estimado</th></tr></thead><tbody><tr><td><a href="./canvas/">Interfaz visual Canvas y A2UI</a></td><td>Comprende el mecanismo de empuje Canvas A2UI, operaciones de interfaz visual e interfaz personalizada</td><td>20 minutos</td></tr><tr><td><a href="./voice-tts/">Activación por voz y texto a voz</a></td><td>Configura Voice Wake, Talk Mode y proveedores TTS, implementa interacción por voz</td><td>15 minutos</td></tr></tbody></table><h3 id="extensiones-inteligentes" tabindex="-1">Extensiones inteligentes <a class="header-anchor" href="#extensiones-inteligentes" aria-label="Permalink to &quot;Extensiones inteligentes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tema</th><th>Descripción</th><th>Tiempo estimado</th></tr></thead><tbody><tr><td><a href="./memory-system/">Sistema de memoria y búsqueda vectorial</a></td><td>Configura y usa el sistema de memoria (SQLite-vec, FTS5, búsqueda híbrida)</td><td>25 minutos</td></tr><tr><td><a href="./skills-platform/">Plataforma de habilidades y ClawdHub</a></td><td>Comprende el sistema de habilidades, habilidades Bundled/Managed/Workspace, integración ClawdHub</td><td>20 minutos</td></tr></tbody></table><h3 id="automatizacion-y-despliegue" tabindex="-1">Automatización y despliegue <a class="header-anchor" href="#automatizacion-y-despliegue" aria-label="Permalink to &quot;Automatización y despliegue&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tema</th><th>Descripción</th><th>Tiempo estimado</th></tr></thead><tbody><tr><td><a href="./cron-automation/">Tareas programadas Cron y Webhook</a></td><td>Configura tareas programadas, activación Webhook, Gmail Pub/Sub y otras funciones de automatización</td><td>20 minutos</td></tr><tr><td><a href="./remote-gateway/">Gateway remoto y Tailscale</a></td><td>Acceso remoto a Gateway a través de Tailscale Serve/Funnel o túnel SSH</td><td>15 minutos</td></tr></tbody></table><h3 id="mecanismos-de-seguridad" tabindex="-1">Mecanismos de seguridad <a class="header-anchor" href="#mecanismos-de-seguridad" aria-label="Permalink to &quot;Mecanismos de seguridad&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tema</th><th>Descripción</th><th>Tiempo estimado</th></tr></thead><tbody><tr><td><a href="./security-sandbox/">Seguridad y aislamiento en sandbox</a></td><td>Comprende el modelo de seguridad, control de permisos de herramientas, aislamiento Sandbox, despliegue con Docker</td><td>20 minutos</td></tr></tbody></table><h2 id="siguientes-pasos" tabindex="-1">Siguientes pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes pasos&quot;">​</a></h2><p>Después de completar el estudio de este capítulo, puedes:</p><ol><li><strong>Estudio en profundidad</strong> - Consulta <a href="./../../faq/troubleshooting/">Solución de problemas</a> para resolver los problemas que encuentres</li><li><strong>Entender el despliegue</strong> - Consulta <a href="./../../appendix/deployment/">Opciones de despliegue</a> para desplegar Clawdbot en entornos de producción</li><li><strong>Desarrollar extensiones</strong> - Consulta <a href="./../../appendix/development/">Guía de desarrollo</a> para aprender a desarrollar complementos y contribuir código</li><li><strong>Ver configuración</strong> - Consulta <a href="./../../appendix/config-reference/">Referencia completa de configuración</a> para conocer todas las opciones de configuración</li></ol><div class="tip custom-block"><p class="custom-block-title">Sugerencia de aprendizaje</p><p>Se recomienda que elijas una ruta de aprendizaje según tus necesidades reales. Si no estás seguro por dónde comenzar, puedes seguir gradualmente la &quot;ruta rápida&quot; y explorar en profundidad otros temas cuando sea necesario.</p></div>',33)])])}const h=a(r,[["render",o]]);export{p as __pageData,h as default};
